import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../api';
import { Trash2, Calendar, UserPlus } from 'lucide-react';

const EmployeeList = () => {
    const [employees, setEmployees] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const fetchEmployees = async () => {
        try {
            setLoading(true);
            const response = await api.get('employees/');
            setEmployees(response.data);
            setError(null);
        } catch (err) {
            setError('Failed to fetch employees.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchEmployees();
    }, []);

    const deleteEmployee = async (id) => {
        if (!window.confirm("Are you sure you want to delete this employee?")) return;
        try {
            await api.delete(`employees/${id}/`);
            setEmployees(employees.filter(emp => emp.id !== id));
        } catch (err) {
            alert('Failed to delete employee.');
        }
    };

    if (loading) {
        return <div className="flex justify-center p-8"><span className="text-gray-500">Loading employees...</span></div>;
    }

    if (error) {
        return <div className="text-red-500 bg-red-50 p-4 rounded-md">{error}</div>;
    }

    return (
        <div>
            <div className="sm:flex sm:items-center">
                <div className="sm:flex-auto">
                    <h2 className="text-xl font-semibold text-gray-900">Employees</h2>
                    <p className="mt-2 text-sm text-gray-700">A list of all employees in the company.</p>
                </div>
                <div className="mt-4 sm:mt-0 sm:ml-16 sm:flex-none">
                    <Link
                        to="/add-employee"
                        className="inline-flex items-center justify-center rounded-md border border-transparent bg-blue-600 px-4 py-2 text-sm font-medium text-white shadow-sm hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 sm:w-auto"
                    >
                        <UserPlus className="-ml-1 mr-2 h-5 w-5" />
                        Add Employee
                    </Link>
                </div>
            </div>

            <div className="mt-8 flex flex-col">
                <div className="-my-2 -mx-4 overflow-x-auto sm:-mx-6 lg:-mx-8">
                    <div className="inline-block min-w-full py-2 align-middle md:px-6 lg:px-8">
                        <div className="overflow-hidden shadow ring-1 ring-black ring-opacity-5 md:rounded-lg">
                            <table className="min-w-full divide-y divide-gray-300">
                                <thead className="bg-gray-50">
                                    <tr>
                                        <th scope="col" className="py-3.5 pl-4 pr-3 text-left text-sm font-semibold text-gray-900 sm:pl-6">ID</th>
                                        <th scope="col" className="px-3 py-3.5 text-left text-sm font-semibold text-gray-900">Name</th>
                                        <th scope="col" className="px-3 py-3.5 text-left text-sm font-semibold text-gray-900">Email</th>
                                        <th scope="col" className="px-3 py-3.5 text-left text-sm font-semibold text-gray-900">Department</th>
                                        <th scope="col" className="relative py-3.5 pl-3 pr-4 sm:pr-6"><span className="sr-only">Actions</span></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-200 bg-white">
                                    {employees.length === 0 ? (
                                        <tr>
                                            <td colSpan="5" className="px-3 py-8 text-center text-gray-500 text-sm">No employees found.</td>
                                        </tr>
                                    ) : employees.map((employee) => (
                                        <tr key={employee.id}>
                                            <td className="whitespace-nowrap py-4 pl-4 pr-3 text-sm font-medium text-gray-900 sm:pl-6">{employee.emp_id}</td>
                                            <td className="whitespace-nowrap px-3 py-4 text-sm text-gray-500">{employee.full_name}</td>
                                            <td className="whitespace-nowrap px-3 py-4 text-sm text-gray-500">{employee.email}</td>
                                            <td className="whitespace-nowrap px-3 py-4 text-sm text-gray-500">
                                               <span className="inline-flex rounded-full bg-blue-100 px-2 leading-5 text-blue-800 font-semibold text-xs border border-blue-200">
                                                  {employee.department}
                                               </span>
                                            </td>
                                            <td className="relative whitespace-nowrap py-4 pl-3 pr-4 text-right text-sm font-medium sm:pr-6 space-x-4">
                                                <Link to={`/employee/${employee.id}/attendance`} className="text-blue-600 hover:text-blue-900" title="View Attendance">
                                                    <Calendar className="h-5 w-5 inline" />
                                                </Link>
                                                <button onClick={() => deleteEmployee(employee.id)} className="text-red-600 hover:text-red-900" title="Delete">
                                                    <Trash2 className="h-5 w-5 inline" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default EmployeeList;
